func newProgramsScopeDriftCmd(flags *rootFlags) *cobra.Command {
	var sinceDays int
	var program string
	var establish bool
	cmd := &cobra.Command{
		Use:         "scope-drift",
		Short:       "Compare stored program scope snapshots",
		Long:        "Establish or compare local program scope snapshots to find assets added and removed since the previous snapshot.",
		Example:     "  yeswehack-pp-cli programs scope-drift --program acme --json\n  yeswehack-pp-cli programs scope-drift --establish-baseline",
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) > 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				return nil
			}
			db, err := openResearchStore()
			if err != nil {
				return err
			}
			defer db.Close()
			programs, err := listResourceObjects(db, "programs", 10000)
			if err != nil {
				return err
			}
			if establish {
				c, err := flags.newClient()
				if err != nil {
					return err
				}
				var saved []string
				for _, p := range programs {
					slug := programSlug(p)
					if slug == "" || (program != "" && slug != program) {
						continue
					}
					body, err := c.Get("/programs/"+slug+"/scopes", nil)
					if err != nil {
						return classifyAPIError(err, flags)
					}
					scopesJSON, err := json.Marshal(rawScopesToMaps(extractResponseData(body)))
					if err != nil {
						return err
					}
					if err := db.SaveScopeSnapshot(slug, scopesJSON); err != nil {
						return err
					}
					saved = append(saved, slug)
				}
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{"saved": saved}, flags)
			}
			result, err := buildScopeDrift(db, program, time.Now().AddDate(0, 0, -sinceDays))
			if err != nil {
				return err
			}
			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return printJSONFiltered(cmd.OutOrStdout(), result, flags)
			}
			for _, row := range result {
				fmt.Fprintf(cmd.OutOrStdout(), "%s\t+%d\t-%d\n", row["program"], len(row["added"].([]string)), len(row["removed"].([]string)))
			}
			return nil
		},
	}
	cmd.Flags().IntVar(&sinceDays, "since-days", 7, "Snapshot lookback window")
	cmd.Flags().StringVar(&program, "program", "", "Program slug")
	cmd.Flags().BoolVar(&establish, "establish-baseline", false, "Fetch live scopes and save a new baseline")
	cmd.Flags().BoolVar(&flags.asJSON, "json", flags.asJSON, "Output as JSON")
	return cmd
}

func buildScopeDrift(db *store.Store, program string, since time.Time) ([]map[string]any, error) {
	var slugs []string
	if program != "" {
		slugs = []string{program}
	} else {
		programs, err := selectedPrograms(db, "")
		if err != nil {
			return nil, err
		}
		for _, p := range programs {
			if slug := programSlug(p); slug != "" {
				slugs = append(slugs, slug)
			}
		}
	}
	var result []map[string]any
	for _, slug := range slugs {
		snaps, err := db.ListScopeSnapshots(slug, since)
		if err != nil {
			return nil, err
		}
		if len(snaps) < 2 {
			result = append(result, map[string]any{
				"program":       slug,
				"added":         []string{},
				"removed":       []string{},
				"modified":      []string{},
				"baseline_note": fmt.Sprintf("No baseline snapshot for %s; run programs scope-drift --establish-baseline first", slug),
			})
			continue
		}
		prev, latest := map[string]scopeAsset{}, map[string]scopeAsset{}
		for _, s := range extractScopesFromSnapshot(snaps[len(snaps)-2]) {
			prev[s.Asset] = s
		}
		for _, s := range extractScopesFromSnapshot(snaps[len(snaps)-1]) {
			latest[s.Asset] = s
		}
		var added, removed, modified []string
		for a, current := range latest {
			if _, ok := prev[a]; !ok {
				added = append(added, a)
			} else if !reflect.DeepEqual(current.Raw, prev[a].Raw) {
				modified = append(modified, a)
			}
		}
		for a := range prev {
			if _, ok := latest[a]; !ok {
				removed = append(removed, a)
			}
		}
		sort.Strings(added)
		sort.Strings(removed)
		sort.Strings(modified)
		result = append(result, map[string]any{"program": slug, "added": added, "removed": removed, "modified": modified})
	}
	return result, nil
}

func rawScopesToMaps(raw json.RawMessage) []map[string]any {
	var arr []map[string]any
	if json.Unmarshal(raw, &arr) == nil {
		return arr
	}
	var obj map[string]any
	if json.Unmarshal(raw, &obj) != nil {
		return nil
	}
	var out []map[string]any
	for _, s := range scopesFromProgram(obj) {
		out = append(out, s.Raw)
	}
	return out
}
